external_knowledge:
- Sales variance refers to the difference between actual sales and sales targets; 
- Performance percentage is calculated as (actual sales / sales target) * 100; 
- Cumulative values are calculated over time, ordered by year and month within each region; 
- The purpose is to analyze and compare the performance of different regions and territories over time.

sql:
SELECT territory_name
FROM sales_territories
WHERE CAST(territory_performance AS REAL) / CAST(territory_target AS REAL) >= 0.7;

SELECT product_id, SUM(extended_amount) AS total_sales, COUNT(order_line_id) AS order_lines, AVG(unit_price) AS average_unit_price
FROM sales_order_details
GROUP BY product_id;

SELECT SUM(actual_sales) AS total_sales
FROM region_months
WHERE region_id = 1 AND year = 2003;

SELECT actual_sales
FROM region_months
WHERE year = 2003 AND month = 'September';

SELECT order_line_id, product_id, quantity, SUM(extended_amount) AS total_extended_amount
FROM sales_order_details
GROUP BY order_line_id, product_id, quantity;

SELECT SUM(extended_amount) AS total_sales_september_2003
FROM sales_order_details
WHERE created_at BETWEEN '2003-09-01 00:00:00' AND '2003-09-30 23:59:59';

SELECT product_id, quantity
FROM sales_order_details
WHERE order_id = 1;

SELECT 
  (SELECT AVG(standard_cost) FROM products) AS average_standard_cost,
  (SELECT product_name FROM products ORDER BY standard_cost DESC LIMIT 1) AS most_expensive_product_name;

SELECT SUM(extended_amount) AS total_sales
FROM sales_order_details
WHERE created_at BETWEEN '2003-10-01 00:00:00' AND '2003-10-31 23:59:59';

SELECT customer_name
FROM customers
WHERE customer_id < 2;
